SELECT

FROM recovery_payment_collection t0 left join law_firm_info t1 on t0.lawyer_id = t1.id and t1.is_deleted = 0
left join project_info t2 on t0.project_id = t2.id and t2.is_deleted = 0


    AND t0.collection_date BETWEEN

      #{item}



    AND (t2.affiliated_org IN
          #{item}
      OR

      t2.manage LIKE CONCAT('%',#{item},'%')

          )


    AND t0.collection_date BETWEEN

      #{item}




    AND t0.flow_state = #{request.flowState}


    AND t1.name  LIKE CONCAT ('%',#{request.lawyerName},'%')



    AND t0.project_id in

      #{item}




    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.collection_status = #{request.collectionStatus}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.lawyer_id = #{request.lawyerId}


    AND t0.lawyer_name LIKE CONCAT ('%',#{request.lawyerName},'%')


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


   AND t0.project_name LIKE CONCAT ('%',#{request.projectName},'%')


  AND t0.project_id = #{request.projectId}


    AND t0.collection_amount = #{request.collectionAmount}


    AND t0.collection_date = #{request.collectionDate}


    AND t0.collection_sign = #{request.collectionSign}


    AND t0.collection_ascription = #{request.collectionAscription}


    AND t0.collection_type = #{request.collectionType}


    AND t0.is_collection_historical = #{request.isCollectionHistorical}


    AND t0.collection_summary = #{request.collectionSummary}


    AND t0.is_deleted = #{request.isDeleted}


    AND t0.remarks = #{request.remarks}


    AND t0.compensatory_cash = #{request.compensatoryCash}


    AND t0.default_cash = #{request.defaultCash}


    AND t0.interest = #{request.interest}


    AND t0.other_fee = #{request.otherFee}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
